function sendToRework(){
   current.work_notes = current.number + gs.getMessage('Tasker -  has been sent to rework') + gs.getUserDisplayName() + gs.getMessage('Tasker - (Reviewer)::') + current.rework_comments;

	current.state = 15;
	current.update();

	gs.addInfoMessage(current.number + gs.getMessage('Tasker -  has been sent to rework'));
	action.setRedirectURL(current);

}
